#!/usr/bin/env python3
"""
Deployment automation script for CI/CD pipeline.
Installs dependencies, runs tests, and packages for deployment.
"""

import subprocess
import sys
import os
import shutil
import hashlib
import tempfile
import logging
from pathlib import Path
from datetime import datetime, timezone

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[logging.StreamHandler(sys.stdout)],
)
logger = logging.getLogger(__name__)

# Configuration
PROJECT_ROOT = Path(__file__).resolve().parent
REQUIREMENTS_FILE = PROJECT_ROOT / "requirements.txt"
TESTS_DIR = PROJECT_ROOT / "tests"
DIST_DIR = PROJECT_ROOT / "dist"
PACKAGE_NAME = "app_deployment"
ALLOWED_COMMANDS = {"pip", "python", "pytest"}


def validate_file_path(filepath: Path, must_exist: bool = True) -> Path:
    """Validate and resolve file path to prevent path traversal."""
    resolved = filepath.resolve()
    # Ensure the path is within the project root
    try:
        resolved.relative_to(PROJECT_ROOT)
    except ValueError:
        raise SecurityError(
            f"Path '{filepath}' resolves outside project root: {resolved}"
        )
    if must_exist and not resolved.exists():
        raise FileNotFoundError(f"Required file not found: {resolved}")
    return resolved


class SecurityError(Exception):
    """Raised when a security check fails."""
    pass


class DeploymentError(Exception):
    """Raised when a deployment step fails."""
    pass


def run_command(args: list[str], cwd: Path | None = None, env: dict | None = None) -> subprocess.CompletedProcess:
    """
    Run a subprocess command securely.
    Uses a list of arguments (no shell=True) to prevent injection.
    """
    if not args:
        raise ValueError("Empty command")

    # Validate the command is in our allowed set
    cmd_name = Path(args[0]).name
    # Allow full python path (e.g., from sys.executable)
    if cmd_name.startswith("python"):
        cmd_name = "python"

    if cmd_name not in ALLOWED_COMMANDS:
        raise SecurityError(f"Command '{cmd_name}' is not in the allowed commands: {ALLOWED_COMMANDS}")

    # Build a clean environment if not provided
    if env is None:
        env = _get_clean_env()

    logger.info("Running: %s", " ".join(str(a) for a in args))

    try:
        result = subprocess.run(
            args,
            cwd=str(cwd) if cwd else str(PROJECT_ROOT),
            env=env,
            capture_output=True,
            text=True,
            timeout=600,  # 10 minute timeout
            shell=False,  # Never use shell=True
        )
    except subprocess.TimeoutExpired as e:
        raise DeploymentError(f"Command timed out after 600s: {e}")
    except OSError as e:
        raise DeploymentError(f"Failed to execute command: {e}")

    if result.stdout:
        for line in result.stdout.strip().split("\n"):
            logger.info("  stdout: %s", line)
    if result.stderr:
        for line in result.stderr.strip().split("\n"):
            logger.warning("  stderr: %s", line)

    if result.returncode != 0:
        raise DeploymentError(
            f"Command failed with return code {result.returncode}: {' '.join(str(a) for a in args)}"
        )

    return result


def _get_clean_env() -> dict[str, str]:
    """Return a minimal, clean environment for subprocesses."""
    clean = {}
    # Only pass through safe, necessary environment variables
    safe_vars = {"PATH", "HOME", "USER", "LANG", "LC_ALL", "VIRTUAL_ENV", "PYTHONPATH", "SYSTEMROOT", "TEMP", "TMP"}
    for var in safe_vars:
        value = os.environ.get(var)
        if value is not None:
            clean[var] = value
    # Ensure reproducible builds
    clean["PYTHONDONTWRITEBYTECODE"] = "1"
    clean["PYTHONHASHSEED"] = "random"
    return clean


def compute_file_checksum(filepath: Path) -> str:
    """Compute SHA-256 checksum of a file."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def validate_requirements_file(filepath: Path) -> None:
    """
    Validate requirements.txt for suspicious entries.
    Checks for common supply-chain attack patterns.
    """
    filepath = validate_file_path(filepath)
    with open(filepath, "r", encoding="utf-8") as f:
        lines = f.readlines()

    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            continue

        # Block requirements that point to arbitrary URLs (potential supply chain risk)
        # Allow only PyPI packages, local files, and trusted indices
        if stripped.startswith(("-e", "--editable")):
            # Editable installs - only allow local paths within project
            parts = stripped.split(maxsplit=1)
            if len(parts) > 1:
                target = parts[1]
                if "://" in target:
                    raise SecurityError(
                        f"Line {line_num}: Editable installs from URLs are not allowed: {stripped}"
                    )
        elif "://" in stripped and not stripped.startswith(("--index-url", "--extra-index-url", "-i", "-f")):
            # Direct URL references - block for security
            raise SecurityError(
                f"Line {line_num}: Direct URL dependencies are not allowed for security: {stripped}"
            )
        elif stripped.startswith(("--index-url", "--extra-index-url", "-i")):
            # Custom index URLs - only allow HTTPS
            if "http://" in stripped:
                raise SecurityError(
                    f"Line {line_num}: Non-HTTPS index URLs are not allowed: {stripped}"
                )

    logger.info("Requirements file validation passed: %s", filepath)


def install_dependencies() -> None:
    """Install project dependencies from requirements.txt securely."""
    logger.info("=" * 60)
    logger.info("STEP 1: Installing dependencies")
    logger.info("=" * 60)

    req_file = validate_file_path(REQUIREMENTS_FILE)
    validate_requirements_file(req_file)

    checksum = compute_file_checksum(req_file)
    logger.info("Requirements file checksum (SHA-256): %s", checksum)

    # Upgrade pip first
    run_command([
        sys.executable, "-m", "pip", "install", "--upgrade", "pip"
    ])

    # Install dependencies with security flags
    run_command([
        sys.executable, "-m", "pip", "install",
        "-r", str(req_file),
        "--no-cache-dir",       # Don't use cached packages
        "--require-hashes" if _requirements_have_hashes(req_file) else "--no-deps",
    ])

    # If we used --no-deps, do a second pass to get transitive deps
    # (This is a tradeoff: --require-hashes is preferred but needs hashes in requirements.txt)
    if not _requirements_have_hashes(req_file):
        logger.info("Installing with full dependency resolution...")
        run_command([
            sys.executable, "-m", "pip", "install",
            "-r", str(req_file),
            "--no-cache-dir",
        ])

    logger.info("Dependencies installed successfully.")


def _requirements_have_hashes(req_file: Path) -> bool:
    """Check if requirements.txt includes hash verification."""
    with open(req_file, "r", encoding="utf-8") as f:
        content = f.read()
    return "--hash=" in content


def run_tests() -> None:
    """Run the project test suite."""
    logger.info("=" * 60)
    logger.info("STEP 2: Running tests")
    logger.info("=" * 60)

    tests_dir = validate_file_path(TESTS_DIR)

    # Check if pytest is available
    try:
        run_command([sys.executable, "-m", "pytest", "--version"])
    except DeploymentError:
        logger.info("pytest not found, installing...")
        run_command([sys.executable, "-m", "pip", "install", "pytest"])

    # Run tests with pytest
    run_command([
        sys.executable, "-m", "pytest",
        str(tests_dir),
        "-v",
        "--tb=short",
        "--strict-markers",
        "-x",  # Stop on first failure for fast feedback
    ])

    logger.info("All tests passed.")


def package_for_deployment() -> Path:
    """Package the application for deployment."""
    logger.info("=" * 60)
    logger.info("STEP 3: Packaging for deployment")
    logger.info("=" * 60)

    # Clean previous dist directory
    dist_dir = PROJECT_ROOT / "dist"
    if dist_dir.exists():
        shutil.rmtree(dist_dir)
    dist_dir.mkdir(parents=True, exist_ok=True)

    timestamp = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
    archive_name = f"{PACKAGE_NAME}_{timestamp}"

    # Collect files to package (exclude sensitive and unnecessary files)
    exclude_patterns = {
        ".git", ".gitignore", "__pycache__", "*.pyc", "*.pyo",
        ".env", ".env.*", "*.secret", "*.key", "*.pem",
        ".pytest_cache", ".mypy_cache", ".tox",
        "node_modules", "dist", ".venv", "venv",
        "*.log", ".DS_Store", "Thumbs.db",
        ".coverage", "htmlcov",
    }

    # Use a temporary directory for staging
    with tempfile.TemporaryDirectory(prefix="deploy_") as staging_dir:
        staging_path = Path(staging_dir) / archive_name

        def should_exclude(path: Path) -> bool:
            """Check if a path should be excluded from the package."""
            for part in path.parts:
                for pattern in exclude_patterns:
                    if pattern.startswith("*"):
                        if part.endswith(pattern[1:]):
                            return True
                    elif part == pattern:
                        return True
            return False

        # Copy files to staging
        file_count = 0
        for item in PROJECT_ROOT.rglob("*"):
            if item.is_file():
                rel_path = item.relative_to(PROJECT_ROOT)
                if should_exclude(rel_path):
                    continue
                dest = staging_path / rel_path
                dest.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(item, dest)
                file_count += 1

        logger.info("Staged %d files for packaging.", file_count)

        if file_count == 0:
            raise DeploymentError("No files found to package. Check project structure.")

        # Create the archive
        archive_path = shutil.make_archive(
            str(dist_dir / archive_name),
            "gztar",
            root_dir=staging_dir,
            base_dir=archive_name,
        )

    archive_file = Path(archive_path)
    checksum = compute_file_checksum(archive_file)

    # Write checksum file
    checksum_file = archive_file.with_suffix(archive_file.suffix + ".sha256")
    checksum_file.write_text(f"{checksum}  {archive_file.name}\n", encoding="utf-8")

    # Set restrictive permissions on the archive
    archive_file.chmod(0o644)
    checksum_file.chmod(0o644)

    size_mb = archive_file.stat().st_size / (1024 * 1024)
    logger.info("Package created: %s (%.2f MB)", archive_file.name, size_mb)
    logger.info("Checksum (SHA-256): %s", checksum)
    logger.info("Checksum file: %s", checksum_file.name)

    return archive_file


def main() -> int:
    """Main deployment pipeline entry point."""
    logger.info("=" * 60)
    logger.info("DEPLOYMENT PIPELINE STARTED")
    logger.info("Project root: %s", PROJECT_ROOT)
    logger.info("Python: %s", sys.version)
    logger.info("Timestamp: %s", datetime.now(timezone.utc).isoformat())
    logger.info("=" * 60)

    steps = [
        ("Install Dependencies", install_dependencies),
        ("Run Tests", run_tests),
        ("Package for Deployment", package_for_deployment),
    ]

    completed_steps = []

    try:
        for step_name, step_func in steps:
            logger.info("Starting: %s", step_name)
            result = step_func()
            completed_steps.append(step_name)
            if result and isinstance(result, Path):
                logger.info("Artifact: %s", result)

        logger.info("=" * 60)
        logger.info("DEPLOYMENT PIPELINE COMPLETED SUCCESSFULLY")
        logger.info("Completed steps: %s", ", ".join(completed_steps))
        logger.info("=" * 60)
        return 0

    except SecurityError as e:
        logger.error("SECURITY ERROR: %s", e)
        logger.error("Pipeline aborted due to security concern.")
        return 2

    except DeploymentError as e:
        logger.error("DEPLOYMENT ERROR: %s", e)
        logger.error("Failed at step: %s", steps[len(completed_steps)][0] if len(completed_steps) < len(steps) else "unknown")
        logger.error("Completed steps before failure: %s", ", ".join(completed_steps) if completed_steps else "none")
        return 1

    except Exception as e:
        logger.exception("UNEXPECTED ERROR: %s", e)
        return 3


if __name__ == "__main__":
    sys.exit(main())